import { defineConfig } from 'vite'
import react from '@vitejs/plugin-react'
import { visualizer } from 'rollup-plugin-visualizer'

// https://vite.dev/config/
export default defineConfig({
  plugins: [
    react(),
    visualizer({
      open: false, // Don't auto-open browser (manual check via stats.html)
      filename: 'dist/stats.html',
      gzipSize: true,
      brotliSize: true,
    })
  ],

  // CSS configuration with PostCSS
  css: {
    postcss: './config/postcss.config.js',
  },

  // Base public path - use '/' for root domain deployment
  base: '/',

  // Build optimizations
  build: {
    // Output directory
    outDir: 'dist',

    // Generate sourcemaps for production debugging (optional)
    sourcemap: false,

    // Chunk size warnings
    chunkSizeWarningLimit: 1000,

    // Rollup options with manual chunking for vendors, UI, and stores
    rollupOptions: {
      output: {
        manualChunks: {
          // Vendor chunk: React core and router
          vendor: ['react', 'react-dom', 'react-router-dom'],

          // UI chunk: Component libraries
          ui: [
            'framer-motion',
            'lucide-react',
            '@dnd-kit/core',
            '@dnd-kit/sortable',
            '@dnd-kit/utilities'
          ],

          // Charts chunk: Heavy visualization libraries
          charts: ['recharts', 'd3'],

          // Canvas chunk: Konva for diagrams
          canvas: ['konva', 'react-konva'],

          // Store chunk: State management
          store: ['zustand', 'dexie']

          // Note: Lexical and XTerm chunked automatically via dynamic imports
        }
      }
    },
  },

  // Development server
  server: {
    port: 5173,
    strictPort: false,
    host: true,
    // Cross-Origin Isolation headers for WebContainer (Phantom Shell)
    // Using 'credentialless' to allow OpenStreetMap tiles while enabling SharedArrayBuffer
    headers: {
      'Cross-Origin-Embedder-Policy': 'credentialless',
      'Cross-Origin-Opener-Policy': 'same-origin',
    },
  },

  // Preview server (for testing production build)
  preview: {
    port: 4173,
    strictPort: false,
    host: true,
  },
})

import { defineConfig } from 'vitest/config';
import react from '@vitejs/plugin-react';

export default defineConfig({
  plugins: [react()],
  test: {
    globals: true,
    environment: 'jsdom',
    setupFiles: ['./config/vitest.setup.ts'],
    css: true,
    // Exclude Playwright E2E tests - they run separately via `npx playwright test`
    exclude: [
      '**/node_modules/**',
      '**/dist/**',
      '**/tests/e2e/**',
    ],
    coverage: {
      provider: 'v8',
      reporter: ['text', 'json', 'html'],
      exclude: [
        'node_modules/',
        'dist/',
        '**/*.d.ts',
        '**/*.config.*',
        '**/mockData/',
        'src/main.tsx',
        'tests/e2e/**',
      ],
    },
  },
});

